defmodule DevOpsAutomationWeb.CommandController do
  use DevOpsAutomationWeb, :controller
  alias DevOpsAutomation.CommandService

  def execute(conn, %{"command" => command_name} = params) do
    args = Map.get(params, "args", %{})
    
    case CommandService.execute_command(command_name, args) do
      {:ok, output} ->
        json(conn, %{status: "success", output: output})
      
      {:error, :command_not_allowed} ->
        conn
        |> put_status(:forbidden)
        |> json(%{status: "error", message: "Command not allowed"})
      
      {:error, {:missing_argument, arg}} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "Missing required argument: #{arg}"})
      
      {:error, {:invalid_argument_type, arg}} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "Invalid argument type for: #{arg}"})
      
      {:error, validation_error} when is_atom(validation_error) ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: "Validation error: #{validation_error}"})
      
      {:error, {exit_code, output}} ->
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{status: "error", exit_code: exit_code, output: output})
      
      {:error, {:system_error, message}} ->
        conn
        |> put_status(:internal_server_error)
        |> json(%{status: "error", message: "System error: #{message}"})
    end
  end

  def list_commands(conn, _params) do
    commands = CommandService.list_available_commands()
    json(conn, commands)
  end
end